class Solution:
    def countPairs(self, n, edges):
        from collections import defaultdict, deque
        adj = defaultdict(list)
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        seen = [False] * n
        total = n * (n - 1) // 2
        same = 0
        for i in range(n):
            if seen[i]:
                continue
            size = 0
            q = deque([i])
            seen[i] = True
            while q:
                u = q.popleft()
                size += 1
                for v in adj[u]:
                    if not seen[v]:
                        seen[v] = True
                        q.append(v)
            same += size * (size - 1) // 2
        return total - same

