class Solution:
    def countPairs(self, n, edges):
        parent = list(range(n))
        rank = [0] * n
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if rank[ra] < rank[rb]:
                ra, rb = rb, ra
            parent[rb] = ra
            if rank[ra] == rank[rb]:
                rank[ra] += 1
        for a, b in edges:
            union(a, b)
        from collections import Counter
        sizes = Counter(find(i) for i in range(n))
        result = 0
        seen = 0
        for c in sizes.values():
            result += c * seen
            seen += c
        return result

